import React, { useRef } from 'react';
import { Container, Typography, Box, Card, CardContent, Chip } from '@mui/material';
import { useNavigate } from 'react-router-dom';
import BusinessIcon from '@mui/icons-material/Business';
import EmojiEventsIcon from '@mui/icons-material/EmojiEvents';
import SchoolIcon from '@mui/icons-material/School';
import FitnessCenterIcon from '@mui/icons-material/FitnessCenter';
import AttachMoneyIcon from '@mui/icons-material/AttachMoney';
import PsychologyIcon from '@mui/icons-material/Psychology';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import SmartToyIcon from '@mui/icons-material/SmartToy';
import AssessmentIcon from '@mui/icons-material/Assessment';
import { C } from '../theme';

function TiltCard({ children, onClick }) {
  const ref = useRef(null);
  const onMove = e => {
    if (!ref.current) return;
    const r = ref.current.getBoundingClientRect();
    const x = (e.clientX - r.left) / r.width - 0.5;
    const y = (e.clientY - r.top)  / r.height - 0.5;
    ref.current.style.transform = `perspective(600px) rotateY(${x*7}deg) rotateX(${-y*7}deg) scale(1.03)`;
    ref.current.style.boxShadow = `${x*-12}px ${y*-12}px 28px rgba(71,133,89,0.18), 0 8px 28px rgba(22,23,72,0.10)`;
  };
  const onLeave = () => {
    if (!ref.current) return;
    ref.current.style.transform = 'perspective(600px) rotateY(0) rotateX(0) scale(1)';
    ref.current.style.boxShadow = '0 2px 12px rgba(22,23,72,0.06)';
  };
  return (
    <Card ref={ref} onClick={onClick} onMouseMove={onMove} onMouseLeave={onLeave}
      sx={{ cursor: 'pointer', bgcolor: C.white, transition: 'transform 0.15s, box-shadow 0.15s' }}>
      {children}
    </Card>
  );
}

const sections = [
  { title: 'Business',    sub: 'Deep-dive ideas & blueprints', icon: <BusinessIcon />,    path: '/business',  color: C.green,     bg: 'rgba(71,133,89,0.1)',   badge: 'Daily' },
  { title: 'Best Idea',   sub: 'Top 3 business models',        icon: <EmojiEventsIcon />, path: '/best-idea', color: '#8b6914',   bg: 'rgba(139,105,20,0.1)',  badge: '🔥 Hot' },
  { title: 'Financial',   sub: 'Track & link your card',        icon: <AttachMoneyIcon />, path: '/financial', color: C.greyBlue,  bg: 'rgba(79,95,118,0.1)',   badge: 'Smart' },
  { title: 'Mindset',     sub: 'Daily mental frameworks',       icon: <PsychologyIcon />,  path: '/mindset',   color: C.purple,    bg: 'rgba(22,23,72,0.08)',   badge: 'Daily' },
  { title: 'Learning',    sub: 'Interactive lessons + quizzes', icon: <SchoolIcon />,      path: '/learning',  color: C.greyBlue,  bg: 'rgba(79,95,118,0.1)',   badge: 'Quiz' },
  { title: 'Health',      sub: 'Workouts + meal plans',         icon: <FitnessCenterIcon />, path: '/health',  color: C.green,     bg: 'rgba(71,133,89,0.1)',   badge: 'Today' },
  { title: 'Check-in',    sub: 'Daily reflection',              icon: <CheckCircleIcon />, path: '/checkin',   color: C.greenDark, bg: 'rgba(45,92,61,0.1)',    badge: '' },
  { title: 'Reports',     sub: 'Your progress overview',        icon: <AssessmentIcon />,  path: '/reports',   color: C.greyBlue,  bg: 'rgba(79,95,118,0.1)',   badge: '' },
  { title: 'AI Advisor',  sub: 'Personal AI coach',             icon: <SmartToyIcon />,    path: '/ai',        color: C.purple,    bg: 'rgba(22,23,72,0.08)',   badge: 'AI' },
];

export default function Dashboard() {
  const navigate = useNavigate();
  const hr = new Date().getHours();
  const greeting = hr < 12 ? 'Good Morning' : hr < 17 ? 'Good Afternoon' : 'Good Evening';
  const today = new Date().toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' });

  return (
    <Container maxWidth="xl" sx={{ py: 2 }}>
      {/* Hero */}
      <Box sx={{
        mb: 5, p: { xs: 3, sm: 4 }, borderRadius: 4,
        background: C.heroGrad,
        position: 'relative', overflow: 'hidden',
        boxShadow: `0 8px 32px rgba(22,23,72,0.22)`,
      }}>
        {/* Decorative blobs inside hero */}
        <Box sx={{ position: 'absolute', top: -60, right: -60, width: 280, height: 280, borderRadius: '50%',
          background: 'rgba(71,133,89,0.18)', filter: 'blur(40px)' }} />
        <Box sx={{ position: 'absolute', bottom: -40, left: '30%', width: 200, height: 200, borderRadius: '50%',
          background: 'rgba(79,95,118,0.15)', filter: 'blur(30px)' }} />

        <Box sx={{ position: 'relative', zIndex: 1 }}>
          <Typography variant="caption" sx={{ color: 'rgba(245,240,232,0.5)', letterSpacing: 3, textTransform: 'uppercase', fontSize: '0.68rem' }}>
            {today}
          </Typography>
          <Typography variant="h3" fontWeight={900} sx={{ color: C.pearl, mt: 0.5, lineHeight: 1.15, fontSize: { xs: '1.8rem', sm: '2.2rem' } }}>
            {greeting}, <span style={{ color: C.greenLight }}>Sirawdink</span> 👋
          </Typography>
          <Typography sx={{ color: 'rgba(245,240,232,0.6)', mt: 1.5, maxWidth: 480, lineHeight: 1.7 }}>
            Everything you need to build, grow, and level up — all in one place.
          </Typography>
          <Box sx={{ display: 'flex', gap: 1, mt: 2.5, flexWrap: 'wrap' }}>
            {['Business Ideas', 'Finance Tracking', 'AI Learning', 'Daily Workouts'].map(tag => (
              <Chip key={tag} label={`✓ ${tag}`} size="small"
                sx={{ bgcolor: 'rgba(71,133,89,0.22)', color: C.greenLight,
                  border: `1px solid rgba(106,171,126,0.35)`, fontWeight: 600 }} />
            ))}
          </Box>
        </Box>
      </Box>

      {/* Module Grid */}
      <Typography variant="overline" sx={{ color: C.greyBlue, letterSpacing: 3, fontWeight: 700, mb: 2, display: 'block' }}>
        Your Modules
      </Typography>
      <Box sx={{ display: 'grid', gap: 2,
        gridTemplateColumns: { xs: 'repeat(2,1fr)', sm: 'repeat(3,1fr)', lg: 'repeat(3,1fr)' } }}>
        {sections.map(s => (
          <TiltCard key={s.title} onClick={() => navigate(s.path)}>
            <CardContent sx={{ p: { xs: 2, sm: 3 } }}>
              <Box sx={{ display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between', mb: 2 }}>
                <Box sx={{ width: 46, height: 46, borderRadius: 3, bgcolor: s.bg,
                  display: 'flex', alignItems: 'center', justifyContent: 'center', color: s.color }}>
                  {s.icon}
                </Box>
                {s.badge && <Chip label={s.badge} size="small"
                  sx={{ bgcolor: s.bg, color: s.color, fontWeight: 700, fontSize: '0.65rem' }} />}
              </Box>
              <Typography fontWeight={700} sx={{ color: C.purple, fontSize: '0.95rem', mb: 0.3 }}>{s.title}</Typography>
              <Typography variant="caption" sx={{ color: C.greyBlue, lineHeight: 1.5 }}>{s.sub}</Typography>
            </CardContent>
          </TiltCard>
        ))}
      </Box>

      {/* Stats */}
      <Box sx={{ mt: 4, display: 'grid', gap: 2,
        gridTemplateColumns: { xs: 'repeat(2,1fr)', sm: 'repeat(4,1fr)' } }}>
        {[
          { label: 'Business Ideas', value: '4+', color: C.green },
          { label: 'Courses',        value: '3',  color: C.greyBlue },
          { label: 'Workout Days',   value: '7',  color: C.greenDark },
          { label: 'AI Ready',       value: '✓',  color: C.purple },
        ].map(s => (
          <Box key={s.label} sx={{ p: 2.5, borderRadius: 3, bgcolor: C.white,
            border: `1px solid ${C.cardBorder}`, textAlign: 'center',
            boxShadow: '0 2px 8px rgba(22,23,72,0.04)',
            transition: 'transform 0.2s', '&:hover': { transform: 'translateY(-2px)' } }}>
            <Typography variant="h4" fontWeight={900} sx={{ color: s.color }}>{s.value}</Typography>
            <Typography variant="caption" fontWeight={600} sx={{ color: C.greyBlue }}>{s.label}</Typography>
          </Box>
        ))}
      </Box>
    </Container>
  );
}
